class CustomDataset(Dataset):
    def __init__(self, data, labels):
        self.data = data
        self.labels = labels
        
    def __len__(self):
        return len(self.data)
        
    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]

def fine_tune_model(model: nn.Module, 
                   train_loader: DataLoader, 
                   val_loader: DataLoader,
                   num_epochs: int = 5,
                   learning_rate: float = 0.001,
                   device: str = 'cpu') -> nn.Module:
    
    model = model.to(device)
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)
    
    model.train()
    for epoch in range(num_epochs):
        total_loss = 0
        for batch_idx, (data, target) in enumerate(train_loader):
            data, target = data.to(device), target.to(device)
            optimizer.zero_grad()
            output = model(data)
            loss = criterion(output, target)
            loss.backward()
            optimizer.step()
            total_loss += loss.item()
            
        if val_loader is not None:
            model.eval()
            val_loss = 0
            correct = 0
            with torch.no_grad():
                for data, target in val_loader:
                    data, target = data.to(device), target.to(device)
                    output = model(data)
                    val_loss += criterion(output, target).item()
                    pred = output.argmax(dim=1, keepdim=True)
                    correct += pred.eq(target.view_as(pred)).sum().item()
                    
            print(f'Epoch {epoch+1}/{num_epochs}, '
                  f'Train Loss: {total_loss/len(train_loader):.4f}, '
                  f'Val Loss: {val_loss/len(val_loader):.4f}, '
                  f'Val Acc: {100.*correct/len(val_loader.dataset):.2f}%')
        else:
            print(f'Epoch {epoch+1}/{num_epochs}, Train Loss: {total_loss/len(train_loader):.4f}')
            
    return model

def get_model_from_huggingface(model_name: str, revision: str = 'main') -> Dict[str, Any]:
    url = f"https://huggingface.co/{model_name}/resolve/{revision}/pytorch_model.bin"
    return load_model_from_url(url)

def save_model(model: nn.Module, path: str):
    torch.save(model.state_dict(), path)
    
def load_model(model_class: nn.Module, path: str, device: str = 'cpu') -> nn.Module:
    model = model_class()
    model.load_state_dict(torch.load(path, map_location=device))
    return model